  ('dietitian-moex-07814', 'dietitian', 'dietitian-moex-100-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '瘦體素（leptin）有抑制食慾的作用，當老鼠瘦體素基因發生缺失時，將因過度攝食而導致肥胖；若為瘦 體素基因異常的肥胖老鼠進行靜脈注射瘦體素之後，其攝食量與體重的變化趨勢為下列何者？', '["攝食量增加，體重增加", "攝食量減少，體重減少", "攝食量增加，體重減少", "攝食量減少，體重增加"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "4e17105d4e39", "answer_pdf_sha1": "10bfdcac6d67", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
