  ('dietitian-moex-07818', 'dietitian', 'dietitian-moex-100-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '卵磷脂（lecithin）經過完全水解後，可產生磷酸、脂肪酸、膽鹼（choline）以及下列何種產物？', '["固醇（sterol）", "甘油（glycerol）", "乙醇胺（ethanolamine）", "絲胺酸（serine）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "4e17105d4e39", "answer_pdf_sha1": "10bfdcac6d67", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07819', 'dietitian', 'dietitian-moex-100-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '利用氧化法測試糖尿病患者尿糖和血糖的濃度時，此法會將葡萄糖轉換為：', '["去氧糖類（deoxy sugars）", "糖醇類（sugar alcohols）", "糖酯類（sugar esters）", "糖酸類（sugar acids）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "4e17105d4e39", "answer_pdf_sha1": "10bfdcac6d67", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07820', 'dietitian', 'dietitian-moex-100-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列有關葡萄糖丙胺酸循環（glucose-alanine cycle）之敘述，何者正確？', '["會消耗葡萄糖以運送丙胺酸至骨骼肌，作為有氧運動時的能源", "會消耗葡萄糖以運送丙胺酸至骨骼肌，作為骨骼蛋白質合成的材料", "是以丙胺酸之型式排除骨骼肌的氨，並換得葡萄糖", "是肝臟以葡萄糖為能源，幫助週邊組織排除氨的方式"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "4e17105d4e39", "answer_pdf_sha1": "10bfdcac6d67", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07821', 'dietitian', 'dietitian-moex-100-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '人體色素細胞中，酪胺酸產生黑色素（melanin）所需酵素與反應為何？', '["酪胺酸轉胺基酶（tyrosine transaminase）；去除胺基", "酪胺酸酶（tyrosinase）；氧化", "酪胺酸脫羧酶（tyrosine decarboxylase）；去除羧基", "酪胺酸羥化酶（tyrosine hydroxlase）；水解"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "4e17105d4e39", "answer_pdf_sha1": "10bfdcac6d67", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07822', 'dietitian', 'dietitian-moex-100-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者是穀胺酸的代謝產物？', '["經去羧化作用產生γ-胺基丁酸（γ-amino butyric acid）", "經去胺基作用產生鳥胺酸（ornithine）", "經羥化反應產生磷酸肌酸（creatine phosphate）", "經氧化反應產生脯胺酸（proline）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "4e17105d4e39", "answer_pdf_sha1": "10bfdcac6d67", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07823', 'dietitian', 'dietitian-moex-100-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者無法降低血漿同半胱胺酸（homocysteine，Hcy）濃度？', '["由5’-甲基四氫葉酸（5’-methyl tetrahydrofolate）提供甲基，使Hcy轉為甲硫胺酸", "由S-腺苷甲硫胺酸（S-adenosyl methionine）提供甲基，使Hcy轉為甲硫胺酸", "由甘胺酸甜菜鹼（glycine betaine）提供甲基，使Hcy轉為甲硫胺酸", "經過轉硫作用（transsulfuration），使Hcy轉為半胱胺酸"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "4e17105d4e39", "answer_pdf_sha1": "10bfdcac6d67", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
